module comparator(obf_a, b, lt, eq, gt);
input [7:0] obf_a, b;
output lt, eq, gt;
reg lt, eq, gt;

always@(obf_a or b) begin
    if (obf_a < b) begin
        lt = 1;
        eq = 0;
        gt = 0;
    end
    else if (obf_a == b) begin
        lt = 0;
        eq = 1;
        gt = 0;
    end
    else begin
        lt = 0;
        eq = 0;
        gt = 1;
    end
end

endmodule
